"use strict";var e=require("../utils/http.js");const t={generate:t=>e.request({url:"/route/generate",method:"POST",data:t,needAuth:!0,showLoading:!1,timeout:12e4}),getDetail:t=>e.request({url:`/route/${t}`,method:"GET",showLoading:!1}),toggleFavorite:(t,r)=>e.request({url:"/route/favorite",method:"POST",data:{userId:t,routeId:r},needAuth:!0}),listMyRoutes:t=>e.request({url:"/route/my",method:"GET",data:{userId:t},needAuth:!0})};exports.routeApi=t;
